// Qlobal scope
const houseKey = "Evin açarı";

// Funksiya scope-u
function kitchen() {
  const teapot = "Çaydan"; // Yalnız funksiya daxilində görünür
  console.log(teapot); // nəticə: Çaydan
  console.log(houseKey); // nəticə: Evin açarı
}
kitchen();

// console.log(teapot); // Xəta: teapot is not defined

// Blok scope-u nümunəsi
if (true) {
  let roomItem = "Lampa"; // Yalnız blok daxilində görünür
  console.log(roomItem); // nəticə: Lampa
}
// console.log(roomItem); // Xəta: roomItem is not defined

// Qlobal scope nümunəsi
var globalItem = "Ümumi açar";
function checkAccess() {
  console.log(globalItem); // nəticə: Ümumi açar
}
checkAccess();
console.log(globalItem); // nəticə: Ümumi açar

// var və let fərqi
for (var i = 0; i < 3; i++) {
  console.log("Dövrün içində i: " + i);
}
console.log("Dövrün xaricində i: " + i); // nəticə: 3

for (let j = 0; j < 3; j++) {
  console.log("Dövrün içində j: " + j);
}
// console.log(j); // Xəta: j is not defined

// Funksiya bəyanatı və scope
function sayHello() {
  console.log("Salam!");
}
sayHello(); // nəticə: Salam!

// Funksiya ifadəsi və scope
if (true) {
  const greet = function() {
    console.log("Salam, qonaq!");
  };
  greet(); // nəticə: Salam, qonaq!
}
// console.log(greet); // Xəta: greet is not defined

