// Global scope
const houseKey = "House key";

// Function scope
function kitchen() {
  const teapot = "Teapot"; // Only visible inside the function
  console.log(teapot); // Output: Teapot
  console.log(houseKey); // Output: House key
}
kitchen();

// console.log(teapot); // Error: teapot is not defined

// Block scope example
if (true) {
  let roomItem = "Lamp"; // Only visible inside the block
  console.log(roomItem); // Output: Lamp
}
// console.log(roomItem); // Error: roomItem is not defined

// Global scope example
var globalItem = "Master key";
function checkAccess() {
  console.log(globalItem); // Output: Master key
}
checkAccess();
console.log(globalItem); // Output: Master key

// Difference between var and let
for (var i = 0; i < 3; i++) {
  console.log("Inside loop i: " + i);
}
console.log("Outside loop i: " + i); // Output: 3

for (let j = 0; j < 3; j++) {
  console.log("Inside loop j: " + j);
}
// console.log(j); // Error: j is not defined

// Function declaration and scope
function sayHello() {
  console.log("Hello!");
}
sayHello(); // Output: Hello!

// Function expression and scope
if (true) {
  const greet = function() {
    console.log("Hello, guest!");
  };
  greet(); // Output: Hello, guest!
}
// console.log(greet); // Error: greet is not defined

