// Глобальная область видимости
const houseKey = "Ключ от дома";

// Область видимости функции
function kitchen() {
  const teapot = "Чайник"; // Видно только внутри функции
  console.log(teapot); // Вывод: Чайник
  console.log(houseKey); // Вывод: Ключ от дома
}
kitchen();

// console.log(teapot); // Ошибка: teapot is not defined

// Пример блочной области видимости
if (true) {
  let roomItem = "Лампа"; // Видно только внутри блока
  console.log(roomItem); // Вывод: Лампа
}
// console.log(roomItem); // Ошибка: roomItem is not defined

// Пример глобальной области видимости
var globalItem = "Главный ключ";
function checkAccess() {
  console.log(globalItem); // Вывод: Главный ключ
}
checkAccess();
console.log(globalItem); // Вывод: Главный ключ

// Разница между var и let
for (var i = 0; i < 3; i++) {
  console.log("Внутри цикла i: " + i);
}
console.log("Вне цикла i: " + i); // Вывод: 3

for (let j = 0; j < 3; j++) {
  console.log("Внутри цикла j: " + j);
}
// console.log(j); // Ошибка: j is not defined

// Объявление функции и scope
function sayHello() {
  console.log("Привет!");
}
sayHello(); // Вывод: Привет!

// Функциональное выражение и scope
if (true) {
  const greet = function() {
    console.log("Привет, гость!");
  };
  greet(); // Вывод: Привет, гость!
}
// console.log(greet); // Ошибка: greet is not defined

